impl From<Opcode> for Instruction {
    fn from(opcode: Opcode) -> Self {
        opcode.as_instruction()
    }
}

impl From<Opcode> for u8 {
    fn from(opcode: Opcode) -> Self {
        opcode.as_u8()
    }
}

impl TryFrom<u8> for Opcode {
    type Error = MarshalError;

    fn try_from(value: u8) -> Result<Self, Self::Error> {
        Self::from_u8(value)
    }
}

